import { createHmac, randomUUID } from "node:crypto";
import { getLocalDevJwtSecret } from "./env";

export const LOCAL_DEV_ISSUER = "anedot-local-dev";
export const LOCAL_DEV_CLIENT_ID = "anedot-local-dev";
const ACCESS_TOKEN_TTL_SECONDS = 60 * 60;

export type LocalDevTokenUse = "access" | "id";

export type LocalDevAccessTokenInput = {
  email: string;
  givenName?: string;
  familyName?: string;
  tokenUse?: LocalDevTokenUse;
  ttlSeconds?: number;
};

/**
 * Mint a Cognito-shaped HS256 JWT for the local development flow.
 *
 * The `anedot_next` Rails backend recognizes this token because its
 * `CognitoJwtValidator` switches to HS256 + `LOCAL_DEV_JWT_SECRET` when
 * `ANEDOT_LOCAL_DEV=true`. Claims mirror what production Cognito access
 * tokens carry so downstream code in the validator and the user creation
 * concern can stay unchanged.
 */
export function signLocalDevAccessToken(
  input: LocalDevAccessTokenInput,
): string {
  const email = input.email.trim();
  if (!email) {
    throw new Error("signLocalDevAccessToken: email is required");
  }

  const secret = getLocalDevJwtSecret();
  const tokenUse: LocalDevTokenUse = input.tokenUse ?? "access";
  const now = Math.floor(Date.now() / 1000);
  const ttl = input.ttlSeconds ?? ACCESS_TOKEN_TTL_SECONDS;

  const header = { alg: "HS256", typ: "JWT" };
  const payload = {
    iss: LOCAL_DEV_ISSUER,
    sub: deriveSubFromEmail(email),
    email,
    email_verified: true,
    given_name: input.givenName ?? "Local",
    family_name: input.familyName ?? "Dev",
    token_use: tokenUse,
    client_id: LOCAL_DEV_CLIENT_ID,
    iat: now,
    exp: now + ttl,
    jti: randomUUID(),
  };

  const signingInput = `${base64url(JSON.stringify(header))}.${base64url(
    JSON.stringify(payload),
  )}`;
  const signature = createHmac("sha256", secret)
    .update(signingInput)
    .digest("base64url");
  return `${signingInput}.${signature}`;
}

export function deriveSubFromEmail(email: string): string {
  return `local-dev|${email.trim().toLowerCase()}`;
}

function base64url(value: string): string {
  return Buffer.from(value).toString("base64url");
}

import { createHmac } from "node:crypto";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import {
  deriveSubFromEmail,
  LOCAL_DEV_CLIENT_ID,
  LOCAL_DEV_ISSUER,
  signLocalDevAccessToken,
} from "./local-dev-jwt";

const SECRET = "local-dev-jwt-secret-at-least-32-characters-long";

const originalSecret = process.env.LOCAL_DEV_JWT_SECRET;

beforeEach(() => {
  process.env.LOCAL_DEV_JWT_SECRET = SECRET;
});

afterEach(() => {
  if (originalSecret === undefined) {
    delete process.env.LOCAL_DEV_JWT_SECRET;
  } else {
    process.env.LOCAL_DEV_JWT_SECRET = originalSecret;
  }
});

function decodeJwt(token: string) {
  const [headerB64, payloadB64, signature] = token.split(".");
  const header = JSON.parse(
    Buffer.from(headerB64, "base64url").toString("utf8"),
  );
  const payload = JSON.parse(
    Buffer.from(payloadB64, "base64url").toString("utf8"),
  );
  return { header, payload, signature, signingInput: `${headerB64}.${payloadB64}` };
}

describe("signLocalDevAccessToken", () => {
  it("produces a Cognito-shaped HS256 JWT", () => {
    const token = signLocalDevAccessToken({ email: "user@example.com" });
    const { header, payload, signature, signingInput } = decodeJwt(token);

    expect(header).toEqual({ alg: "HS256", typ: "JWT" });
    expect(payload.iss).toBe(LOCAL_DEV_ISSUER);
    expect(payload.client_id).toBe(LOCAL_DEV_CLIENT_ID);
    expect(payload.token_use).toBe("access");
    expect(payload.sub).toBe("local-dev|user@example.com");
    expect(payload.email).toBe("user@example.com");
    expect(payload.email_verified).toBe(true);
    expect(payload.given_name).toBe("Local");
    expect(payload.family_name).toBe("Dev");
    expect(typeof payload.iat).toBe("number");
    expect(typeof payload.exp).toBe("number");
    expect(payload.exp - payload.iat).toBe(60 * 60);
    expect(typeof payload.jti).toBe("string");

    const expected = createHmac("sha256", SECRET)
      .update(signingInput)
      .digest("base64url");
    expect(signature).toBe(expected);
  });

  it("derives sub deterministically per email", () => {
    const a = signLocalDevAccessToken({ email: "Same@Example.com" });
    const b = signLocalDevAccessToken({ email: "same@example.com" });
    expect(decodeJwt(a).payload.sub).toBe(decodeJwt(b).payload.sub);
    expect(decodeJwt(a).payload.sub).toBe("local-dev|same@example.com");
  });

  it("supports id token shape via tokenUse", () => {
    const token = signLocalDevAccessToken({
      email: "user@example.com",
      tokenUse: "id",
    });
    expect(decodeJwt(token).payload.token_use).toBe("id");
  });

  it("uses provided names when given", () => {
    const token = signLocalDevAccessToken({
      email: "user@example.com",
      givenName: "Ada",
      familyName: "Lovelace",
    });
    const { payload } = decodeJwt(token);
    expect(payload.given_name).toBe("Ada");
    expect(payload.family_name).toBe("Lovelace");
  });

  it("throws when email is empty", () => {
    expect(() => signLocalDevAccessToken({ email: "  " })).toThrow();
  });

  it("throws when LOCAL_DEV_JWT_SECRET is missing", () => {
    delete process.env.LOCAL_DEV_JWT_SECRET;
    expect(() =>
      signLocalDevAccessToken({ email: "user@example.com" }),
    ).toThrow(/LOCAL_DEV_JWT_SECRET/);
  });

  it("throws when LOCAL_DEV_JWT_SECRET is too short", () => {
    process.env.LOCAL_DEV_JWT_SECRET = "short";
    expect(() =>
      signLocalDevAccessToken({ email: "user@example.com" }),
    ).toThrow(/at least 32 characters/);
  });
});

describe("deriveSubFromEmail", () => {
  it("lowercases and prefixes", () => {
    expect(deriveSubFromEmail("Foo@Bar.COM")).toBe("local-dev|foo@bar.com");
  });
});

